div.script:
(function() {
    var inp = document.getElementById('vpFileInput');
    var txt = document.getElementById('vpDropText');
    var zone = document.getElementById('vpDropzone');
    if (!inp) return;
    inp.addEventListener('change', function() {
        if (inp.files.length) { txt.textContent = inp.files[0].name; zone.style.borderColor = 'var(--vp-accent)'; }
    });
    ['dragover','dragenter'].forEach(function(e){
        zone.addEventListener(e, function(ev){ ev.preventDefault(); zone.classList.add('drag-over'); });
    });
    ['dragleave','drop'].forEach(function(e){
        zone.addEventListener(e, function(){ zone.classList.remove('drag-over'); });
    });
})();
